// themes.js -- the six cousin theme songs, baked from their original MIDI arrangements into
// compact packed data (no external .mid files any more), plus the shared chip-voice synth.
//
// Two consumers import this:
//   * /policies  -- plays a song straight through ONCE, closing sting chord and all ("as-is").
//   * the game   -- the SAME tracks as the run in-game music: the body run twice (the second
//                   pass thickened with an octave lead), then looped, with the sting dropped.
//
// Each note is packed as 5x Uint16: [ch, note, vel, t*100 (centisec), d*100], base64 encoded.
// Channels match the arrangements: 0 lead, 1 bass, 2 pad, 3 counter, 9 GM drums.

const DATA = {
  blingo: { dur: 155.682, bpm: 88, program: {"0":80,"1":38,"2":90,"3":46,"9":0}, b64: "" },
  blazo: { dur: 135.826, bpm: 115, program: {"0":81,"1":38,"2":90,"3":46,"9":0}, b64: "" },
  blizzy: { dur: 157.067, bpm: 75, program: {"0":82,"1":39,"2":90,"3":46,"9":0}, b64: "" },
  blomba: { dur: 151.692, bpm: 65, program: {"0":83,"1":39,"2":90,"3":46,"9":0}, b64: "" },
  bloopy: { dur: 143.088, bpm: 136, program: {"0":80,"1":38,"2":90,"3":46,"9":0}, b64: "" },
  blondie: { dur: 137, bpm: 100, program: {"0":83,"1":39,"2":90,"3":46,"9":0}, b64: "" },
};

const _cache = {};
function _unpack(b64) {
  const bin = atob(b64), len = bin.length, bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) bytes[i] = bin.charCodeAt(i);
  return new Uint16Array(bytes.buffer);
}
// decoded song: { notes:[{ch,note,vel,t,d}], duration, program, bpm }. Cached per id.
export function getSong(id) {
  if (_cache[id]) return _cache[id];
  const rec = DATA[id] || DATA.blingo;
  const u = _unpack(rec.b64), notes = [];
  for (let i = 0; i < u.length; i += 5)
    notes.push({ ch: u[i], note: u[i + 1], vel: u[i + 2], t: u[i + 3] / 100, d: u[i + 4] / 100 });
  const song = { notes, duration: rec.dur, program: rec.program, bpm: rec.bpm };
  _cache[id] = song;
  return song;
}
export const THEME_IDS = Object.keys(DATA);

// where the closing sting chord begins -- the point the in-game loop cuts the body at, so the
// track never lands on that held "the end" chord and just rolls back into the loop instead.
export function songBodyEnd(song) {
  let maxT = 0;
  for (const n of song.notes) if (n.t > maxT) maxT = n.t;
  // the sting is the final SUSTAINED chord: long notes that all strike near the last onset
  let e = Infinity;
  for (const n of song.notes) if (n.d > 1.4 && n.t > maxT - 0.4 && n.t < e) e = n.t;
  return isFinite(e) ? e : song.duration;
}

// ---- shared chip voices: the same five-voice palette the arrangements were written for ----
export const LEAD_WAVE = { 80: "square", 81: "sawtooth", 82: "sine", 83: "triangle" };
const _hz = m => 440 * Math.pow(2, (m - 69) / 12);
const _noise = new WeakMap();
function _noiseBuf(ctx) {
  let b = _noise.get(ctx);
  if (!b) {
    const n = ctx.sampleRate; b = ctx.createBuffer(1, n, ctx.sampleRate);
    const d = b.getChannelData(0);
    for (let i = 0; i < n; i++) d[i] = Math.random() * 2 - 1;
    _noise.set(ctx, b);
  }
  return b;
}
// a pitched voice (lead / bass / pad / counter), scheduled at absolute time "when" on "dest".
// gainMul scales it (the game octave-doubled loop layer rides in quieter at ~0.5).
export function themeVoice(ctx, dest, n, program, when, gainMul = 1) {
  const prog = program[n.ch];
  let type = "square", gain = 0.12, atk = 0.005, tail = 0.02, pad = false;
  if (n.ch === 0) { type = LEAD_WAVE[prog] || "square"; gain = 0.16; }
  else if (n.ch === 1) { type = "triangle"; gain = 0.24; }
  else if (n.ch === 2) { type = "sine"; gain = 0.045; atk = 0.05; pad = true; }
  else if (n.ch === 3) { type = "triangle"; gain = 0.08; }
  const o = ctx.createOscillator(); o.type = type; o.frequency.value = _hz(n.note);
  const g = ctx.createGain(); const vol = gain * (n.vel / 127) * gainMul;
  g.gain.setValueAtTime(0.0001, when);
  g.gain.linearRampToValueAtTime(vol, when + atk);
  if (pad) g.gain.setValueAtTime(vol, when + n.d * 0.55);
  g.gain.exponentialRampToValueAtTime(0.0001, when + n.d + tail);
  o.connect(g); g.connect(dest);
  o.start(when); o.stop(when + n.d + tail + 0.03);
}
// a GM drum voice (kick 36, snare 38/39, hats 42/46, crash 49).
export function themeDrum(ctx, dest, note, when, vel, gainMul = 1) {
  const v = (vel / 127) * gainMul;
  const nsrc = () => { const s = ctx.createBufferSource(); s.buffer = _noiseBuf(ctx); return s; };
  const env = (node, peak, dec) => {
    const g = ctx.createGain(); g.gain.setValueAtTime(peak * v, when);
    g.gain.exponentialRampToValueAtTime(0.0001, when + dec);
    node.connect(g); g.connect(dest); return g;
  };
  if (note === 36) {
    const o = ctx.createOscillator(); o.type = "sine";
    o.frequency.setValueAtTime(140, when); o.frequency.exponentialRampToValueAtTime(45, when + 0.11);
    env(o, 0.9, 0.15); o.start(when); o.stop(when + 0.17);
  } else if (note === 38 || note === 39) {
    const s = nsrc(); const bp = ctx.createBiquadFilter();
    bp.type = "bandpass"; bp.frequency.value = note === 38 ? 1800 : 1300; bp.Q.value = 0.8;
    s.connect(bp); env(bp, 0.5, note === 38 ? 0.15 : 0.10); s.start(when); s.stop(when + 0.18);
    if (note === 38) { const o = ctx.createOscillator(); o.type = "triangle"; o.frequency.value = 185;
      env(o, 0.18, 0.10); o.start(when); o.stop(when + 0.12); }
  } else if (note === 42 || note === 46) {
    const s = nsrc(); const hp = ctx.createBiquadFilter(); hp.type = "highpass"; hp.frequency.value = 7000;
    const dec = note === 42 ? 0.03 : 0.16; s.connect(hp); env(hp, 0.22, dec); s.start(when); s.stop(when + dec + 0.03);
  } else if (note === 49) {
    const s = nsrc(); const hp = ctx.createBiquadFilter(); hp.type = "highpass"; hp.frequency.value = 5000;
    s.connect(hp); env(hp, 0.3, 0.6); s.start(when); s.stop(when + 0.62);
  }
}
